SET standard_conforming_strings = OFF;
DROP TABLE IF EXISTS "public"."start" CASCADE;
BEGIN;
CREATE TABLE "public"."start" ( "ogc_fid" SERIAL, CONSTRAINT "start_pk" PRIMARY KEY ("ogc_fid") );
SELECT AddGeometryColumn('public','start','wkb_geometry',4326,'POINT',2);
CREATE INDEX "start_wkb_geometry_geom_idx" ON "public"."start" USING GIST ("wkb_geometry");
ALTER TABLE "public"."start" ADD COLUMN "uuiid" VARCHAR(255);
ALTER TABLE "public"."start" ADD COLUMN "name" VARCHAR(255);
ALTER TABLE "public"."start" ADD COLUMN "popupcontent" VARCHAR;
ALTER TABLE "public"."start" ADD COLUMN "amenity" VARCHAR;
COMMIT;
